class XorBase {
private:
	array<int, 21> a;    // 线性基基底
	array<int, 21> pos;  // 基底对应最晚出现的下标 
	static constexpr int MN = 20;
public:
	XorBase() {
		fill(a.begin(), a.end(), 0);
		fill(pos.begin(), pos.end(), 0);
	};

	int& operator[](int x) {
		return a[x];
	}

	// 插入新数
	void insert(int x, int idx) {
		if (!x)return;
		for (int i = MN; i >= 0; i--)
			if (x & (1ll << i)) {
				if (!a[i]) {
					// 线性基里没有 x，插入 x
					a[i] = x;
					pos[i] = idx;
					return;
				}
				// 【重点】：新下标放在高位，老下标去低位
				if (idx > pos[i]) {
					swap(idx, pos[i]);
					swap(x, a[i]);
				}
				x ^= a[i]; // 线性基里有 x
			}
	}

	// 线性基合并
	friend XorBase operator +(XorBase& x, XorBase& y) {
		XorBase z = x;
		for (int i = MN; i >= 0; i--)
			if (y[i])
				z.insert(y[i], y.pos[i]);
		return z;
	}

	// 查是否存在线性基内
	bool check(long long x, int L) {
		for (int i = MN; i >= 0; i--)
			if (x & (1ll << i))
				if (!a[i])return false;
				else {
					if (pos[i] >= L)x ^= a[i];
					else return false;
				}
		return true;
	}
};
void solve(int CASE)
{
	int n; cin >> n;
	var a = vector<int>(n + 1);
	fa(i, 1, n)cin >> a[i];
	var g = vector<vector<int>>(n + 1);
	fa(i, 1, n - 1) {
		int u, v; cin >> u >> v;
		g[u].pb(v), g[v].pb(u);
	}

	var lca = LCA(n, g);
	var xb = vector<XorBase>(n + 1);
	var dfs = [&](var dfs, int now, int fa)->void {
		xb[now] = xb[fa];
		xb[now].insert(a[now], lca.depth[now]);
		for (int to : g[now]) {
			if (to == fa)continue;
			dfs(dfs, to, now);
		}
		};
	dfs(dfs, 1, 0);

	int q; cin >> q;
	while (q--) {
		int x, y, k; cin >> x >> y >> k;
		if (lca.depth[x] > lca.depth[y])swap(x, y);
		int l = lca.lca(x, y);
		if (x == l) {
			int L = lca.depth[x];
			if (xb[y].check(k, L))cout << "YES" << endl;
			else cout << "NO" << endl;
		}
		else {
			int L = lca.depth[l];
			var res = xb[x] + xb[y];
			if (res.check(k, L))cout << "YES" << endl;
			else cout << "NO" << endl;
		}
	}
	return;
}
